"use client";

import { useState } from "react";
import { Popover, Transition } from "@headlessui/react";
import { useSession, signOut } from "next-auth/react";
import apiClient from "@/libs/api";

// A button to show user some account actions
//  1. Billing: open a Stripe Customer Portal to manage their billing (cancel subscription, update payment method, etc.).
//     You have to manually activate the Customer Portal in your Stripe Dashboard (https://dashboard.stripe.com/test/settings/billing/portal)
//     This is only available if the customer has a customerId (they made a purchase previously)
//  2. Logout: sign out and go back to homepage
// See more at https://shipfa.st/docs/components/buttonAccount
const ButtonAccount = () => {
	const { data: session, status } = useSession();
	const [isLoading, setIsLoading] = useState(false);

	const handleSignOut = () => {
		signOut({ callbackUrl: "/" });
	};
	const handleBilling = async () => {
		setIsLoading(true);

		try {
			const { url } = await apiClient.post("/stripe/create-portal", {
				returnUrl: window.location.href,
			});

			window.location.href = url;
		} catch (e) {
			console.error(e);
		}

		setIsLoading(false);
	};

	// Don't show anything if not authenticated (we don't have any info about the user)
	if (status === "unauthenticated") return null;

	return (
		<Popover className="relative z-10">
			{({ open }) => (
				<>
					<Popover.Button className="btn">
						{session?.user?.image ? (
							<img
								src={session?.user?.image}
								alt={session?.user?.name || "Account"}
								className="w-6 h-6 rounded-full shrink-0"
								referrerPolicy="no-referrer"
								width={24}
								height={24}
							/>
						) : (
							<span className="w-6 h-6 bg-base-300 flex justify-center items-center rounded-full shrink-0">
								{session?.user?.name?.charAt(0) ||
									session?.user?.email?.charAt(0)}
							</span>
						)}

						{session?.user?.name || "Account"}

						{isLoading ? (
							<span className="loading loading-spinner loading-xs"></span>
						) : (
							<svg
								xmlns="http://www.w3.org/2000/svg"
								viewBox="0 0 20 20"
								fill="currentColor"
								className={`w-5 h-5 duration-200 opacity-50 ${
									open ? "transform rotate-180 " : ""
								}`}
							>
								<path
									fillRule="evenodd"
									d="M5.23 7.21a.75.75 0 011.06.02L10 11.168l3.71-3.938a.75.75 0 111.08 1.04l-4.25 4.5a.75.75 0 01-1.08 0l-4.25-4.5a.75.75 0 01.02-1.06z"
									clipRule="evenodd"
								/>
							</svg>
						)}
					</Popover.Button>
					<Transition
						enter="transition duration-100 ease-out"
						enterFrom="transform scale-95 opacity-0"
						enterTo="transform scale-100 opacity-100"
						leave="transition duration-75 ease-out"
						leaveFrom="transform scale-100 opacity-100"
						leaveTo="transform scale-95 opacity-0"
					>
						<Popover.Panel className="absolute left-0 z-10 mt-3 w-screen max-w-[16rem] transform">
							<div className="overflow-hidden rounded-xl shadow-xl ring-1 ring-base-content/10 bg-base-100 p-1">
								<div className="space-y-0.5 text-sm">
									<button
										className="flex items-center gap-2 hover:bg-base-300 duration-200 py-1.5 px-4 w-full rounded-lg font-medium cursor-pointer"
										onClick={handleBilling}
									>
										<svg
											xmlns="http://www.w3.org/2000/svg"
											viewBox="0 0 20 20"
											fill="currentColor"
											className="w-5 h-5"
										>
											<path
												fillRule="evenodd"
												d="M2.5 4A1.5 1.5 0 001 5.5V6h18v-.5A1.5 1.5 0 0017.5 4h-15zM19 8.5H1v6A1.5 1.5 0 002.5 16h15a1.5 1.5 0 001.5-1.5v-6zM3 13.25a.75.75 0 01.75-.75h1.5a.75.75 0 010 1.5h-1.5a.75.75 0 01-.75-.75zm4.75-.75a.75.75 0 000 1.5h3.5a.75.75 0 000-1.5h-3.5z"
												clipRule="evenodd"
											/>
										</svg>
										Billing
									</button>
									<button
										className="flex items-center gap-2 hover:bg-error/20 hover:text-error duration-200 py-1.5 px-4 w-full rounded-lg font-medium cursor-pointer"
										onClick={handleSignOut}
									>
										<svg
											xmlns="http://www.w3.org/2000/svg"
											viewBox="0 0 20 20"
											fill="currentColor"
											className="w-5 h-5"
