  // CreateGroup
  const group = await createGroup({ name: "AI Conferences", keywords: ["ai", "ml", "nlp"] });
  assert(group.id, "Group ID fehlt");
  console.log("✅ CreateGroup:", group.id);

  // UserJoinGroup
